__kernel void dynproc_kernel(
    int iteration,
    __global const int* gpuWall,
    __global int* gpuSrc,
    __global int* gpuResults,
    int cols,
    int rows,
    int startStep,
    int border,
    int HALO,
    __local int* prev,
    __local int* result,
    __global int* outputBuffer)
{
    size_t gid = get_global_id(0);
    if (gid != 0) return;

    (void)rows;
    (void)border;
    (void)HALO;
    (void)prev;
    (void)result;

    __global int* src = gpuSrc;
    __global int* dst = gpuResults;

    for (int t = 0; t < iteration; t++) {
        int wall_row = startStep + t;
        int base = wall_row * cols;

        for (int n = 0; n < cols; n++) {
            int m = src[n];
            if (n > 0) {
                int v = src[n - 1];
                m = (m <= v) ? m : v;
            }
            if (n < cols - 1) {
                int v = src[n + 1];
                m = (m <= v) ? m : v;
            }
            dst[n] = gpuWall[base + n] + m;
        }

        __global int* tmp = src;
        src = dst;
        dst = tmp;
    }

    if ((iteration & 1) == 0) {
        for (int n = 0; n < cols; n++) {
            gpuResults[n] = src[n];
        }
    }

    if (outputBuffer != 0) {
        outputBuffer[0] = 0;
    }
}
